  1→import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
  2→
  3→const corsHeaders = {
  4→  'Access-Control-Allow-Origin': '*',
  5→  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
  6→};
  7→
  8→Deno.serve(async (req) => {
  9→  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });
 10→
 11→  try {
 12→    const supabase = createClient(
 13→      Deno.env.get('SUPABASE_URL')!,
 14→      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
 15→    );
 16→
 17→    const { campaign_id } = await req.json();
 18→    if (!campaign_id) return new Response(JSON.stringify({ error: 'Missing campaign_id' }), { status: 400, headers: corsHeaders });
 19→
 20→    const { data: campaign } = await supabase.from('campaigns').select('*').eq('id', campaign_id).single();
 21→    if (!campaign) return new Response(JSON.stringify({ error: 'Campaign not found' }), { status: 404, headers: corsHeaders });
 22→
 23→    const { data: cards } = await supabase
 24→      .from('customer_cards')
 25→      .select('customer_id, created_at, last_activity, tier, customers(push_token), loyalty_programs!inner(merchant_id)')
 26→      .eq('loyalty_programs.merchant_id', campaign.merchant_id);
 27→
 28→    // Apply segment filtering based on campaign target_segment
 29→    const now = new Date();
 30→    const filteredCards = (cards ?? []).filter((c: any) => {
 31→      switch (campaign.target_segment) {
 32→        case 'new': {
 33→          if (!c.created_at) return false;
 34→          const createdAt = new Date(c.created_at);
 35→          const daysSinceCreation = (now.getTime() - createdAt.getTime()) / (1000 * 60 * 60 * 24);
 36→          return daysSinceCreation <= 30;
 37→        }
 38→        case 'inactive': {
 39→          if (!c.last_activity) return true; // no activity at all counts as inactive
 40→          const lastActivity = new Date(c.last_activity);
 41→          const daysSinceActivity = (now.getTime() - lastActivity.getTime()) / (1000 * 60 * 60 * 24);
 42→          return daysSinceActivity > 14;
 43→        }
 44→        case 'vip': {
 45→          const tier = (c.tier ?? '').toLowerCase();
 46→          return tier === 'gold' || tier === 'vip';
 47→        }
 48→        case 'all':
 49→        default:
 50→          return true;
 51→      }
 52→    });
 53→
 54→    const tokens = filteredCards
 55→      .map((c: any) => c.customers?.push_token)
 56→      .filter(Boolean) as string[];
 57→
 58→    if (!tokens.length) {
 59→      return new Response(JSON.stringify({ sent: 0 }), { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
 60→    }
 61→
 62→    const messages = tokens.map((token) => ({
 63→      to: token,
 64→      title: campaign.title,
 65→      body: campaign.body,
 66→      data: { campaign_id: campaign.id, type: 'campaign' },
 67→    }));
 68→
 69→    await fetch('https://exp.host/--/api/v2/push/send', {
 70→      method: 'POST',
 71→      headers: { 'Content-Type': 'application/json' },
 72→      body: JSON.stringify(messages),
 73→    });
 74→
 75→    const notifications = filteredCards.map((c: any) => ({
 76→      customer_id: c.customer_id,
 77→      campaign_id: campaign.id,
 78→      title: campaign.title,
 79→      body: campaign.body,
 80→      type: 'campaign' as const,
 81→    }));
 82→
 83→    if (notifications.length) {
 84→      await supabase.from('notifications').insert(notifications);
 85→    }
 86→
 87→    await supabase.from('campaigns').update({
 88→      status: 'sent',
 89→      sent_at: new Date().toISOString(),
 90→    }).eq('id', campaign.id);
 91→
 92→    return new Response(JSON.stringify({ sent: tokens.length }), {
 93→      status: 200,
 94→      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
 95→    });
 96→
 97→  } catch (err) {
 98→    return new Response(JSON.stringify({ error: (err as Error).message }), { status: 500, headers: corsHeaders });
 99→  }
100→});
