-- A/B Testing support for campaigns
-- Adds variant identifier and parent campaign reference

alter table public.campaigns add column if not exists variant char(1) default null;
alter table public.campaigns add column if not exists parent_campaign_id uuid references public.campaigns(id);

-- Index for quick lookup of B variants by parent
create index if not exists idx_campaigns_parent on public.campaigns(parent_campaign_id)
  where parent_campaign_id is not null;

'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';

type Segment = 'all' | 'new' | 'inactive' | 'vip';

const SEGMENT_LABELS: Record<Segment, string> = {
  all: 'All Clients',
  new: 'New Clients (joined < 30 days)',
  inactive: 'Inactive Clients (no activity > 14 days)',
  vip: 'VIP Clients (Gold / VIP tier)',
};

const SEGMENT_BUTTON_LABELS: Record<Segment, string> = {
  all: 'Send to All Clients',
  new: 'Send to New Clients',
  inactive: 'Send to Inactive Clients',
  vip: 'Send to VIP Clients',
};

export function CampaignForm({ merchantId }: { merchantId: string }) {
  const [title, setTitle] = useState('');
  const [body, setBody] = useState('');
  const [segment, setSegment] = useState<Segment>('all');
  const [loading, setLoading] = useState(false);
  const [abEnabled, setAbEnabled] = useState(false);
  const [titleB, setTitleB] = useState('');
  const [bodyB, setBodyB] = useState('');
  const router = useRouter();
  const supabase = createClient();

  async function handleSend(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);

    try {
      if (abEnabled) {
        // --- A/B Test: create two campaign rows ---
        const { data: campaignA, error: errA } = await supabase
          .from('campaigns')
          .insert({
            merchant_id: merchantId,
            title,
            body,
            type: 'push',
            target_segment: segment,
            status: 'draft',
            variant: 'A',
          })
          .select()
          .single();

        if (errA || !campaignA) {
          setLoading(false);
          return;
        }

        const { data: campaignB, error: errB } = await supabase
          .from('campaigns')
          .insert({
            merchant_id: merchantId,
            title: titleB,
            body: bodyB,
            type: 'push',
            target_segment: segment,
            status: 'draft',
            variant: 'B',
            parent_campaign_id: campaignA.id,
          })
          .select()
          .single();

        if (errB || !campaignB) {
          setLoading(false);
          return;
        }

        await supabase.functions.invoke('send-push', {
          body: {
            campaign_id: campaignA.id,
            ab_test: true,
            variant_b_id: campaignB.id,
          },
        });
      } else {
        // --- Standard single campaign ---
        const { data: campaign, error } = await supabase
          .from('campaigns')
          .insert({
            merchant_id: merchantId,
            title,
            body,
            type: 'push',
            target_segment: segment,
            status: 'draft',
          })
          .select()
          .single();

        if (error || !campaign) {
          setLoading(false);
          return;
        }

        await supabase.functions.invoke('send-push', {
          body: { campaign_id: campaign.id },
        });
      }

      setTitle('');
      setBody('');
      setTitleB('');
      setBodyB('');
      setSegment('all');
      setAbEnabled(false);
      setLoading(false);
      router.refresh();
    } catch {
      setLoading(false);
    }
  }

  return (
    <form onSubmit={handleSend} className="space-y-4 max-w-lg p-4 border rounded-lg">
      <h3 className="font-semibold">Send Push Notification</h3>

      {/* A/B toggle */}
      <div className="flex items-center gap-2">
        <input
          id="ab-toggle"
          type="checkbox"
          checked={abEnabled}
          onChange={(e) => setAbEnabled(e.target.checked)}
          className="h-4 w-4 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500"
        />
        <Label htmlFor="ab-toggle">Enable A/B Test</Label>
      </div>

      {abEnabled ? (
        <>
          {/* Variant A */}
          <fieldset className="space-y-2 border rounded-md p-3">
            <legend className="px-1 text-sm font-medium text-indigo-700">
              Variant A
            </legend>
            <div>
              <Label>Title (A)</Label>
              <Input
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="e.g. Weekend Special!"
                required
              />
            </div>
            <div>
              <Label>Message (A)</Label>
              <Textarea
                value={body}
                onChange={(e) => setBody(e.target.value)}
                placeholder="e.g. 20% off all items this weekend!"
                required
              />
            </div>
          </fieldset>

          {/* Variant B */}
          <fieldset className="space-y-2 border rounded-md p-3">
            <legend className="px-1 text-sm font-medium text-indigo-700">
              Variant B
            </legend>
            <div>
              <Label>Title (B)</Label>
              <Input
                value={titleB}
                onChange={(e) => setTitleB(e.target.value)}
                placeholder="e.g. Flash Sale!"
                required
              />
            </div>
            <div>
              <Label>Message (B)</Label>
              <Textarea
                value={bodyB}
                onChange={(e) => setBodyB(e.target.value)}
                placeholder="e.g. Save 20% this weekend only!"
                required
              />
            </div>
          </fieldset>
        </>
      ) : (
        <>
          <div>
            <Label>Title</Label>
            <Input
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="e.g. Weekend Special!"
              required
            />
          </div>
          <div>
            <Label>Message</Label>
            <Textarea
              value={body}
              onChange={(e) => setBody(e.target.value)}
              placeholder="e.g. 20% off all items this weekend!"
              required
            />
          </div>
        </>
      )}

      {/* Segment selector (shared for both modes) */}
      <div>
        <Label>Target Segment</Label>
        <Select value={segment} onValueChange={(value) => setSegment(value as Segment)}>
          <SelectTrigger className="w-full">
            <SelectValue placeholder="Select a segment" />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">{SEGMENT_LABELS.all}</SelectItem>
            <SelectItem value="new">{SEGMENT_LABELS.new}</SelectItem>
            <SelectItem value="inactive">{SEGMENT_LABELS.inactive}</SelectItem>
            <SelectItem value="vip">{SEGMENT_LABELS.vip}</SelectItem>
          </SelectContent>
        </Select>
      </div>

      <Button type="submit" disabled={loading}>
        {loading
          ? 'Sending...'
          : abEnabled
            ? `A/B Test - ${SEGMENT_BUTTON_LABELS[segment]}`
            : SEGMENT_BUTTON_LABELS[segment]}
      </Button>
    </form>
  );
}

import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

/**
 * Shuffle an array in-place using Fisher-Yates and return it.
 */
function shuffle<T>(arr: T[]): T[] {
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
}

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
    );

    const { campaign_id, ab_test, variant_b_id } = await req.json();
    if (!campaign_id) return new Response(JSON.stringify({ error: 'Missing campaign_id' }), { status: 400, headers: corsHeaders });

    const { data: campaign } = await supabase.from('campaigns').select('*').eq('id', campaign_id).single();
    if (!campaign) return new Response(JSON.stringify({ error: 'Campaign not found' }), { status: 404, headers: corsHeaders });

    // Fetch filtered audience (shared for both modes)
    const { data: cards } = await supabase
      .from('customer_cards')
      .select('customer_id, created_at, last_activity, tier, customers(push_token), loyalty_programs!inner(merchant_id)')
      .eq('loyalty_programs.merchant_id', campaign.merchant_id);

    const now = new Date();
    const filteredCards = (cards ?? []).filter((c: any) => {
      switch (campaign.target_segment) {
        case 'new': {
          if (!c.created_at) return false;
          const createdAt = new Date(c.created_at);
          const daysSinceCreation = (now.getTime() - createdAt.getTime()) / (1000 * 60 * 60 * 24);
          return daysSinceCreation <= 30;
        }
        case 'inactive': {
          if (!c.last_activity) return true;
          const lastActivity = new Date(c.last_activity);
          const daysSinceActivity = (now.getTime() - lastActivity.getTime()) / (1000 * 60 * 60 * 24);
          return daysSinceActivity > 14;
        }
        case 'vip': {
          const tier = (c.tier ?? '').toLowerCase();
          return tier === 'gold' || tier === 'vip';
        }
        case 'all':
        default:
          return true;
      }
    });

    // ---------- A/B Test path ----------
    if (ab_test && variant_b_id) {
      const { data: campaignB } = await supabase.from('campaigns').select('*').eq('id', variant_b_id).single();
      if (!campaignB) return new Response(JSON.stringify({ error: 'Variant B campaign not found' }), { status: 404, headers: corsHeaders });

      // Shuffle and split audience 50/50
      shuffle(filteredCards);
      const midpoint = Math.ceil(filteredCards.length / 2);
      const groupA = filteredCards.slice(0, midpoint);
      const groupB = filteredCards.slice(midpoint);

      const tokensA = groupA.map((c: any) => c.customers?.push_token).filter(Boolean) as string[];
      const tokensB = groupB.map((c: any) => c.customers?.push_token).filter(Boolean) as string[];

      // Send variant A
      if (tokensA.length) {
        const messagesA = tokensA.map((token) => ({
          to: token,
          title: campaign.title,
          body: campaign.body,
          data: { campaign_id: campaign.id, type: 'campaign' },
        }));
        await fetch('https://exp.host/--/api/v2/push/send', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(messagesA),
        });
      }

      // Send variant B
      if (tokensB.length) {
        const messagesB = tokensB.map((token) => ({
          to: token,
          title: campaignB.title,
          body: campaignB.body,
          data: { campaign_id: campaignB.id, type: 'campaign' },
        }));
        await fetch('https://exp.host/--/api/v2/push/send', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(messagesB),
        });
      }

      // Record notifications for variant A
      const notificationsA = groupA.map((c: any) => ({
        customer_id: c.customer_id,
        campaign_id: campaign.id,
        title: campaign.title,
        body: campaign.body,
        type: 'campaign' as const,
      }));

      // Record notifications for variant B
      const notificationsB = groupB.map((c: any) => ({
        customer_id: c.customer_id,
        campaign_id: campaignB.id,
        title: campaignB.title,
        body: campaignB.body,
        type: 'campaign' as const,
      }));

      const allNotifications = [...notificationsA, ...notificationsB];
      if (allNotifications.length) {
        await supabase.from('notifications').insert(allNotifications);
      }

      // Mark both campaigns as sent
      const sentAt = new Date().toISOString();
      await supabase.from('campaigns').update({ status: 'sent', sent_at: sentAt }).eq('id', campaign.id);
      await supabase.from('campaigns').update({ status: 'sent', sent_at: sentAt }).eq('id', campaignB.id);

      return new Response(
        JSON.stringify({ sent: tokensA.length + tokensB.length, variant_a: tokensA.length, variant_b: tokensB.length }),
        { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    // ---------- Standard (non-A/B) path ----------
    const tokens = filteredCards
      .map((c: any) => c.customers?.push_token)
      .filter(Boolean) as string[];

    if (!tokens.length) {
      return new Response(JSON.stringify({ sent: 0 }), { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
    }

    const messages = tokens.map((token) => ({
      to: token,
      title: campaign.title,
      body: campaign.body,
      data: { campaign_id: campaign.id, type: 'campaign' },
    }));

    await fetch('https://exp.host/--/api/v2/push/send', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(messages),
    });

    const notifications = filteredCards.map((c: any) => ({
      customer_id: c.customer_id,
      campaign_id: campaign.id,
      title: campaign.title,
      body: campaign.body,
      type: 'campaign' as const,
    }));

    if (notifications.length) {
      await supabase.from('notifications').insert(notifications);
    }

    await supabase.from('campaigns').update({
      status: 'sent',
      sent_at: new Date().toISOString(),
    }).eq('id', campaign.id);

    return new Response(JSON.stringify({ sent: tokens.length }), {
      status: 200,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });

  } catch (err) {
    return new Response(JSON.stringify({ error: (err as Error).message }), { status: 500, headers: corsHeaders });
  }
});

import { createClient } from '@/lib/supabase/server';
import { redirect } from 'next/navigation';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';

interface Campaign {
  id: string;
  title: string;
  body: string;
  variant: string | null;
  parent_campaign_id: string | null;
  opens: number;
  clicks: number;
  status: string;
  sent_at: string | null;
  created_at: string;
}

interface ABPair {
  a: Campaign;
  b: Campaign;
  winnerOpen: 'A' | 'B' | 'tie';
  winnerClick: 'A' | 'B' | 'tie';
}

function rate(numerator: number, denominator: number): string {
  if (denominator === 0) return '0.0%';
  return ((numerator / denominator) * 100).toFixed(1) + '%';
}

function determineWinner(valA: number, valB: number): 'A' | 'B' | 'tie' {
  if (valA > valB) return 'A';
  if (valB > valA) return 'B';
  return 'tie';
}

export default async function ABResultsPage() {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) redirect('/login');

  const { data: merchant } = await supabase
    .from('merchants')
    .select('id')
    .eq('user_id', user.id)
    .single();

  if (!merchant) redirect('/login');

  // Fetch all campaigns that are part of an A/B test
  const { data: abCampaigns } = await supabase
    .from('campaigns')
    .select('*')
    .eq('merchant_id', merchant.id)
    .not('variant', 'is', null)
    .order('created_at', { ascending: false });

  // Group into pairs: variant A (parent) + variant B (child referencing parent)
  const pairs: ABPair[] = [];
  const campaignMap = new Map<string, Campaign>();
  for (const c of (abCampaigns ?? []) as Campaign[]) {
    campaignMap.set(c.id, c);
  }

  // Find all A variants (variant === 'A' and no parent_campaign_id)
  for (const c of (abCampaigns ?? []) as Campaign[]) {
    if (c.variant === 'A' && !c.parent_campaign_id) {
      // Find its B child
      const bChild = (abCampaigns ?? []).find(
        (b: Campaign) => b.parent_campaign_id === c.id && b.variant === 'B'
      ) as Campaign | undefined;
      if (bChild) {
        // Simple comparison using opens and clicks stored on the campaign row
        // In a production app you would count notifications with read_at, etc.
        const totalA = Math.max(c.opens + c.clicks, 1);
        const totalB = Math.max(bChild.opens + bChild.clicks, 1);
        pairs.push({
          a: c,
          b: bChild,
          winnerOpen: determineWinner(c.opens, bChild.opens),
          winnerClick: determineWinner(c.clicks, bChild.clicks),
        });
      }
    }
  }

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">A/B Test Results</h1>

      {pairs.length === 0 ? (
        <p className="text-gray-500">
          No A/B tests found. Create one from the Campaigns page.
        </p>
      ) : (
        <div className="space-y-6">
          {pairs.map((pair) => (
            <Card key={pair.a.id}>
              <CardHeader>
                <CardTitle className="text-base">
                  A/B Test &mdash;{' '}
                  {pair.a.sent_at
                    ? new Date(pair.a.sent_at).toLocaleDateString()
                    : 'Draft'}
                </CardTitle>
              </CardHeader>
              <CardContent>
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Metric</TableHead>
                      <TableHead>Variant A</TableHead>
                      <TableHead>Variant B</TableHead>
                      <TableHead>Winner</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    <TableRow>
                      <TableCell className="font-medium">Title</TableCell>
                      <TableCell>{pair.a.title}</TableCell>
                      <TableCell>{pair.b.title}</TableCell>
                      <TableCell />
                    </TableRow>
                    <TableRow>
                      <TableCell className="font-medium">Opens</TableCell>
                      <TableCell
                        className={
                          pair.winnerOpen === 'A'
                            ? 'text-green-600 font-semibold'
                            : ''
                        }
                      >
                        {pair.a.opens}
                      </TableCell>
                      <TableCell
                        className={
                          pair.winnerOpen === 'B'
                            ? 'text-green-600 font-semibold'
                            : ''
                        }
                      >
                        {pair.b.opens}
                      </TableCell>
                      <TableCell>
                        {pair.winnerOpen === 'tie' ? (
                          <Badge variant="secondary">Tie</Badge>
                        ) : (
                          <Badge variant="default">
                            Variant {pair.winnerOpen}
                          </Badge>
                        )}
                      </TableCell>
                    </TableRow>
                    <TableRow>
                      <TableCell className="font-medium">Clicks</TableCell>
                      <TableCell
                        className={
                          pair.winnerClick === 'A'
                            ? 'text-green-600 font-semibold'
                            : ''
                        }
                      >
                        {pair.a.clicks}
                      </TableCell>
                      <TableCell
                        className={
                          pair.winnerClick === 'B'
                            ? 'text-green-600 font-semibold'
                            : ''
                        }
                      >
                        {pair.b.clicks}
                      </TableCell>
                      <TableCell>
                        {pair.winnerClick === 'tie' ? (
                          <Badge variant="secondary">Tie</Badge>
                        ) : (
                          <Badge variant="default">
                            Variant {pair.winnerClick}
                          </Badge>
                        )}
                      </TableCell>
                    </TableRow>
                    <TableRow>
                      <TableCell className="font-medium">Open Rate</TableCell>
                      <TableCell>
                        {rate(pair.a.opens, pair.a.opens + pair.a.clicks)}
                      </TableCell>
                      <TableCell>
                        {rate(pair.b.opens, pair.b.opens + pair.b.clicks)}
                      </TableCell>
                      <TableCell />
                    </TableRow>
                    <TableRow>
                      <TableCell className="font-medium">Click Rate</TableCell>
                      <TableCell>
                        {rate(pair.a.clicks, pair.a.opens + pair.a.clicks)}
                      </TableCell>
                      <TableCell>
                        {rate(pair.b.clicks, pair.b.opens + pair.b.clicks)}
                      </TableCell>
                      <TableCell />
                    </TableRow>
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}

